messages.sparqlQuery:
PREFIX le: <http://linked.earth/ontology#>
PREFIX arch: <http://linked.earth/ontology/archive#>
PREFIX geo: <http://www.w3.org/2003/01/geo/wgs84_pos#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?dataset ?datasetName ?latitude ?longitude
WHERE {
  ?dataset a le:Dataset .
  ?dataset le:hasArchiveType arch:Coral .
  OPTIONAL { ?dataset le:hasName ?datasetName . }
  OPTIONAL {
    ?dataset le:hasLocation ?location .
    OPTIONAL { ?location geo:lat ?latitude . }
    OPTIONAL { ?location geo:long ?longitude . }
  }
  # Filtering by country "India" is not directly supported by a
  # property in the provided ontology structure, nor are geographic
  # bounds for India provided. The query retrieves coral datasets
  # and their locations if available.
}
